"""Главный цикл text2sql-агента на основе tool calling."""

from __future__ import annotations

import json
import sys
from dataclasses import dataclass, field
from typing import Any

from .config import Config
from .db import OracleClient
from .llm import LLMClient
from .schema_doc import few_shot_examples, short_schema_digest
from .tools import TOOL_SPECS, AgentState, ToolExecutor


SYSTEM_PROMPT_TEMPLATE = """\
Ты — text2sql ассистент банковской аналитики. Твоя задача — отвечать на вопросы
пользователя реальными цифрами из базы Oracle XE через инструменты.

Правила:
1. Используй ТОЛЬКО tools — не выдумывай SQL и цифры в текстовом ответе.
2. Перед написанием SQL уточни схему: при сомнениях вызывай inspect_schema.
3. Пиши Oracle SQL: даты как DATE '2025-06-30', верхняя граница строк — FETCH FIRST n ROWS ONLY.
4. Для поиска по подстроке используй UPPER(col) LIKE UPPER('%шаблон%').
5. Помни про "ИТОГОВЫЕ ПОЛЯ": нельзя суммировать вместе агрегат и его компоненты
   (например, PNL_SUM с PL_CA, или CA_LCY_SUM с CA_LCY_RUB_SUM).
6. Балансы (CA_LCY_SUM, DEP_SUM) — это среднемесячные значения; сравнения «на дату»
   через них не имеют смысла, используй конкретный MONTH_DT.
7. Если в вопросе не указан период — используй последний доступный месяц
   (SELECT MAX(MONTH_DT) FROM client_product).
8. После execute_sql ВСЕГДА вызови validate_result с разумными ожиданиями,
   затем final_answer с конкретными числами и единицами.
9. Если SQL вернул ошибку — изучи её, исправь и повтори. Если повторно пусто —
   убедись, что период/фильтр корректны, и честно сообщи об этом в final_answer.
10. Финальный текст — на русском, кратко, с цифрами и интерпретацией.
    Большие суммы форматируй как «1 234 567 890.12 ₽».

Краткая сводка единственной таблицы (полное описание доступно через inspect_schema):
{schema_digest}

Примеры пар (вопрос → SQL):
{examples}
"""


@dataclass
class AgentResult:
    answer: str
    supporting_data: dict[str, Any]
    iterations: int
    query_history: list[dict[str, Any]] = field(default_factory=list)


class Text2SQLAgent:
    def __init__(
        self,
        config: Config | None = None,
        max_iterations: int = 12,
        verbose: bool = True,
    ):
        self.config = config or Config.from_env()
        self.max_iterations = max_iterations
        self.verbose = verbose
        self.db = OracleClient(self.config)
        self.llm = LLMClient(self.config)
        self.state = AgentState()
        self.executor = ToolExecutor(db=self.db, state=self.state)

    def _log(self, *parts: Any) -> None:
        if self.verbose:
            print(*parts, file=sys.stderr, flush=True)

    def _system_prompt(self) -> str:
        return SYSTEM_PROMPT_TEMPLATE.format(
            schema_digest=short_schema_digest("client_product"),
            examples=few_shot_examples("client_product", limit=10),
        )

    def ask(self, question: str) -> AgentResult:
        messages: list[dict[str, Any]] = [
            {"role": "system", "content": self._system_prompt()},
            {"role": "user", "content": question.strip()},
        ]

        iteration = 0
        no_tool_strikes = 0
        with self.db:
            for iteration in range(1, self.max_iterations + 1):
                self._log(f"--- iter {iteration} ---")
                # После 2-х подряд "пустых" ответов без tool-вызовов
                # принудительно требуем вызов final_answer.
                if no_tool_strikes >= 2:
                    tool_choice: str | dict[str, Any] = {
                        "type": "function",
                        "function": {"name": "final_answer"},
                    }
                else:
                    tool_choice = "auto"
                resp = self.llm.chat(
                    messages=messages,
                    tools=TOOL_SPECS,
                    tool_choice=tool_choice,
                )
                choice = resp.choices[0]
                msg = choice.message
                tool_calls = msg.tool_calls or []

                assistant_msg: dict[str, Any] = {"role": "assistant", "content": msg.content or ""}
                if tool_calls:
                    assistant_msg["tool_calls"] = [
                        {
                            "id": tc.id,
                            "type": "function",
                            "function": {
                                "name": tc.function.name,
                                "arguments": tc.function.arguments or "{}",
                            },
                        }
                        for tc in tool_calls
                    ]
                messages.append(assistant_msg)

                if not tool_calls:
                    if self.state.final_text:
                        break
                    no_tool_strikes += 1
                    self._log(
                        f"LLM не вызвала tools (strike {no_tool_strikes}), "
                        "пушим к final_answer"
                    )
                    hint = (
                        "Ты не вызвал ни одного инструмента. Не отвечай простым "
                        "текстом — это запрещено. Сейчас вызови final_answer "
                        "с финальным русскоязычным текстом и supporting_data "
                        "на основе данных, уже полученных через execute_sql."
                    )
                    if self.state.last_result is None:
                        hint = (
                            "Ты не вызвал ни одного инструмента и ещё не выполнил "
                            "SQL. Вызови inspect_schema или execute_sql."
                        )
                    messages.append({"role": "user", "content": hint})
                    continue
                else:
                    no_tool_strikes = 0

                for tc in tool_calls:
                    name = tc.function.name
                    raw_args = tc.function.arguments or "{}"
                    try:
                        args = json.loads(raw_args) if raw_args else {}
                    except json.JSONDecodeError:
                        args = {}
                    self._log(f"tool: {name} args={_short(raw_args)}")
                    result_str = self.executor.dispatch(name, args)
                    self._log(f"  -> {_short(result_str, 240)}")
                    messages.append(
                        {
                            "role": "tool",
                            "tool_call_id": tc.id,
                            "content": result_str,
                        }
                    )

                if self.state.final_text is not None:
                    break
            else:
                self._log("Достигнут лимит итераций без final_answer")

        if not self.state.final_text:
            # Последний фолбэк — синтезируем ответ из last_result.
            self.state.final_text = self._fallback_answer()

        return AgentResult(
            answer=self.state.final_text or "Не удалось получить ответ.",
            supporting_data=self.state.final_supporting_data or {},
            iterations=iteration,
            query_history=list(self.state.query_history),
        )

    def _fallback_answer(self) -> str:
        if self.state.last_result is None:
            return "Не удалось выполнить запрос — нет результата."
        r = self.state.last_result
        head = ", ".join(r.columns)
        body = "; ".join(
            ", ".join(str(v) for v in row) for row in r.rows[:5]
        )
        return f"Результат запроса: колонки [{head}], строки: {body}"


def run_question(
    question: str,
    config: Config | None = None,
    verbose: bool = True,
) -> AgentResult:
    agent = Text2SQLAgent(config=config, verbose=verbose)
    return agent.ask(question)


def _short(s: str, n: int = 160) -> str:
    s = " ".join(s.split())
    return s if len(s) <= n else s[: n - 1] + "…"

"""Тонкая обёртка над oracledb для выполнения SELECT-запросов."""

from __future__ import annotations

import datetime as _dt
from dataclasses import dataclass, field
from decimal import Decimal
from typing import Any

import oracledb

from .config import Config


class SQLExecutionError(RuntimeError):
    """Ошибка выполнения SQL — отдаётся агенту как контролируемый сигнал."""


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool = False
    sql: str = ""
    elapsed_ms: float = 0.0

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
            "elapsed_ms": round(self.elapsed_ms, 2),
        }


@dataclass
class OracleClient:
    config: Config
    max_rows: int = 200
    _connection: oracledb.Connection | None = field(default=None, repr=False)

    def connect(self) -> oracledb.Connection:
        if self._connection is None:
            self._connection = oracledb.connect(
                user=self.config.oracle_user,
                password=self.config.oracle_password,
                dsn=self.config.oracle_dsn,
            )
        return self._connection

    def close(self) -> None:
        if self._connection is not None:
            try:
                self._connection.close()
            finally:
                self._connection = None

    def __enter__(self) -> "OracleClient":
        self.connect()
        return self

    def __exit__(self, *exc: Any) -> None:
        self.close()

    @staticmethod
    def _normalize_sql(sql: str) -> str:
        s = sql.strip()
        # Стрипаем markdown-обёртки ```sql ... ``` если LLM вернула их.
        if s.startswith("```"):
            s = s.split("\n", 1)[1] if "\n" in s else s.lstrip("`")
            if s.endswith("```"):
                s = s[: -3]
        s = s.strip().rstrip(";").strip()
        return s

    @staticmethod
    def _assert_safe_select(sql: str) -> None:
        upper = sql.upper().lstrip()
        if not (upper.startswith("SELECT") or upper.startswith("WITH")):
            raise SQLExecutionError(
                "Разрешены только SELECT/WITH запросы — нашли начало: "
                + upper.split()[0]
            )
        forbidden = (
            " INSERT ",
            " UPDATE ",
            " DELETE ",
            " MERGE ",
            " DROP ",
            " ALTER ",
            " CREATE ",
            " TRUNCATE ",
            " GRANT ",
            " REVOKE ",
        )
        padded = " " + " ".join(upper.split()) + " "
        for kw in forbidden:
            if kw in padded:
                raise SQLExecutionError(f"Запрещённое ключевое слово: {kw.strip()}")

    @classmethod
    def _convert_value(cls, v: Any) -> Any:
        if v is None:
            return None
        if isinstance(v, (_dt.datetime, _dt.date)):
            return v.isoformat()
        if isinstance(v, Decimal):
            f = float(v)
            return int(f) if f.is_integer() else f
        if isinstance(v, oracledb.LOB):
            return v.read()
        return v

    def execute(self, sql: str) -> QueryResult:
        import time

        normalized = self._normalize_sql(sql)
        self._assert_safe_select(normalized)
        conn = self.connect()
        cur = conn.cursor()
        start = time.perf_counter()
        try:
            cur.execute(normalized)
            columns = [str(d[0]) for d in (cur.description or [])]
            fetched = cur.fetchmany(self.max_rows + 1)
        except oracledb.DatabaseError as e:
            (err,) = e.args
            raise SQLExecutionError(f"Oracle error: {err.message.strip()}") from e
        finally:
            cur.close()
        elapsed_ms = (time.perf_counter() - start) * 1000.0

        truncated = len(fetched) > self.max_rows
        if truncated:
            fetched = fetched[: self.max_rows]
        rows = [[self._convert_value(v) for v in row] for row in fetched]
        return QueryResult(
            columns=columns,
            rows=rows,
            row_count=len(rows),
            truncated=truncated,
            sql=normalized,
            elapsed_ms=elapsed_ms,
        )

"""Определения tools и их исполнители для агента.

В терминах OpenAI Chat Completions API инструменты описаны JSON Schema-ой
в TOOL_SPECS, а вызовы маршрутизируются в ToolExecutor.
"""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any

from .db import OracleClient, QueryResult, SQLExecutionError
from .schema_doc import get_table_doc, list_tables
from .validation import validate


TOOL_SPECS: list[dict[str, Any]] = [
