@dataclass
class AgentState:
    last_result: QueryResult | None = None
    query_history: list[dict[str, Any]] = field(default_factory=list)
    final_text: str | None = None
    final_supporting_data: dict[str, Any] | None = None


@dataclass
class ToolExecutor:
    db: OracleClient
    state: AgentState = field(default_factory=AgentState)

    def dispatch(self, name: str, arguments: dict[str, Any]) -> str:
        """Вызывает соответствующий tool и сериализует ответ в JSON-строку."""
        handler = {
            "inspect_schema": self._inspect_schema,
            "execute_sql": self._execute_sql,
            "validate_result": self._validate_result,
            "final_answer": self._final_answer,
        }.get(name)
        if handler is None:
            return json.dumps(
                {"error": f"Неизвестный tool: {name}"},
                ensure_ascii=False,
            )
        try:
            result = handler(arguments)
        except Exception as exc:  # noqa: BLE001
            result = {"error": f"{type(exc).__name__}: {exc}"}
        return json.dumps(result, ensure_ascii=False, default=str)

    def _inspect_schema(self, args: dict[str, Any]) -> dict[str, Any]:
        table = (args.get("table") or "client_product").strip()
        available = list_tables()
        if table.lower() not in {t.lower() for t in available}:
            return {
                "error": f"Таблица '{table}' не описана в metadata.py",
                "available_tables": available,
            }
        return get_table_doc(table.lower())

    def _execute_sql(self, args: dict[str, Any]) -> dict[str, Any]:
        sql = args.get("sql") or ""
        if not sql.strip():
            return {"error": "Пустой SQL"}
        try:
            result = self.db.execute(sql)
        except SQLExecutionError as exc:
            self.state.query_history.append({"sql": sql, "error": str(exc)})
            return {"error": str(exc), "sql": sql}
        self.state.last_result = result
        self.state.query_history.append(
            {
                "sql": result.sql,
                "row_count": result.row_count,
                "elapsed_ms": round(result.elapsed_ms, 2),
            }
        )
        out = result.to_dict()
        # LLM достаточно первых ~20 строк, чтобы понять структуру ответа
        # — но row_count и columns всегда полные.
        preview_rows = out["rows"][:20]
        return {
            "columns": out["columns"],
            "row_count": out["row_count"],
            "rows_preview": preview_rows,
            "rows_in_preview": len(preview_rows),
            "truncated": out["truncated"],
            "elapsed_ms": out["elapsed_ms"],
        }

    def _validate_result(self, args: dict[str, Any]) -> dict[str, Any]:
        report = validate(self.state.last_result, args)
        return report.to_dict()

    def _final_answer(self, args: dict[str, Any]) -> dict[str, Any]:
        text = (args.get("text") or "").strip()
        supporting = args.get("supporting_data") or {}
        if not text:
            return {"error": "Параметр text обязателен"}
        self.state.final_text = text
        self.state.final_supporting_data = (
            supporting if isinstance(supporting, dict) else {"value": supporting}
        )
        return {"accepted": True}

"""Детерминированные sanity-проверки результата SQL."""

from __future__ import annotations

from dataclasses import dataclass
from numbers import Number
from typing import Any

from .db import QueryResult


@dataclass
class ValidationReport:
    ok: bool
    issues: list[str]
    notes: list[str]

    def to_dict(self) -> dict[str, Any]:
        return {"ok": self.ok, "issues": self.issues, "notes": self.notes}


def validate(
    result: QueryResult | None,
    expectations: dict[str, Any] | None = None,
) -> ValidationReport:
    """Прогоняет набор детерминированных проверок над последним QueryResult.

    expectations поддерживает (все опционально):
      - min_rows: int — минимальное число строк
      - max_rows: int — максимальное число строк
      - non_null_columns: list[str] — эти колонки не должны быть полностью NULL
      - numeric_ranges: {col: [min, max]} — все ненуль-значения col в [min, max]
      - expected_columns: list[str] — указанные колонки должны присутствовать
    """
    issues: list[str] = []
    notes: list[str] = []
    expectations = expectations or {}

    if result is None:
        return ValidationReport(False, ["Нет результата для валидации"], [])

    notes.append(f"row_count={result.row_count}, columns={result.columns}")

    min_rows = expectations.get("min_rows", 1)
    if isinstance(min_rows, int) and result.row_count < min_rows:
        issues.append(
            f"Слишком мало строк: {result.row_count} < ожидаемых {min_rows}"
        )

    max_rows = expectations.get("max_rows")
    if isinstance(max_rows, int) and result.row_count > max_rows:
        issues.append(
            f"Слишком много строк: {result.row_count} > {max_rows}"
        )

    expected_cols = expectations.get("expected_columns") or []
    if expected_cols:
        missing = [c for c in expected_cols if c.upper() not in {x.upper() for x in result.columns}]
        if missing:
            issues.append(f"В результате нет ожидаемых колонок: {missing}")

    non_null_cols = expectations.get("non_null_columns") or []
    for col in non_null_cols:
        col_idx = _find_col(result.columns, col)
        if col_idx is None:
            issues.append(f"Колонки {col} нет в результате — non_null проверка не выполнена")
            continue
        values = [row[col_idx] for row in result.rows]
        if values and all(v is None for v in values):
            issues.append(f"Колонка {col} полностью NULL")

    ranges = expectations.get("numeric_ranges") or {}
    for col, bounds in ranges.items():
        if not (isinstance(bounds, (list, tuple)) and len(bounds) == 2):
            continue
        lo, hi = bounds
        col_idx = _find_col(result.columns, col)
        if col_idx is None:
            issues.append(f"numeric_ranges: колонка {col} не найдена")
            continue
        for row in result.rows:
            v = row[col_idx]
            if v is None:
                continue
            if not isinstance(v, Number):
                issues.append(f"numeric_ranges: значение {col}={v!r} не число")
                break
            if (lo is not None and v < lo) or (hi is not None and v > hi):
                issues.append(
                    f"numeric_ranges: {col}={v} вне диапазона [{lo}, {hi}]"
                )
                break

    # Универсальная sanity-проверка: если результат — одна агрегированная
    # строка из одного числа, оно не должно быть NULL.
    if result.row_count == 1 and len(result.columns) == 1:
        v = result.rows[0][0]
        if v is None:
            issues.append("Единственное скалярное значение в результате — NULL")

    if result.truncated:
        notes.append("Результат был усечён max_rows — возможно, имеет смысл уточнить запрос")

