def _find_col(columns: list[str], name: str) -> int | None:
    target = name.upper()
    for i, c in enumerate(columns):
        if c.upper() == target:
            return i
    return None

"""Загрузка конфигурации из .env."""

from __future__ import annotations

import os
from dataclasses import dataclass
from pathlib import Path

from dotenv import load_dotenv


@dataclass(frozen=True)
class Config:
    oracle_user: str
    oracle_password: str
    oracle_dsn: str
    api_url: str
    api_key: str
    sql_model: str
    response_model: str

    @classmethod
    def from_env(cls, env_path: str | os.PathLike[str] | None = None) -> "Config":
        if env_path is None:
            cwd_env = Path.cwd() / ".env"
            if cwd_env.exists():
                env_path = cwd_env
            else:
                env_path = Path(__file__).resolve().parent.parent / ".env"
        load_dotenv(dotenv_path=env_path, override=False)

        missing = [
            k
            for k in (
                "AI_ANALYST_ORACLE_USERNAME",
                "AI_ANALYST_ORACLE_PASSWORD",
                "AI_ANALYST_ORACLE_DSN",
                "AI_ANALYST_API_URL",
                "AI_ANALYST_API_KEY",
                "AI_ANALYST_SQL_MODEL",
            )
            if not os.environ.get(k)
        ]
        if missing:
            raise RuntimeError(
                f"Не заданы обязательные переменные окружения: {', '.join(missing)}. "
                f"Проверьте {env_path}."
            )

        return cls(
            oracle_user=os.environ["AI_ANALYST_ORACLE_USERNAME"],
            oracle_password=os.environ["AI_ANALYST_ORACLE_PASSWORD"],
            oracle_dsn=os.environ["AI_ANALYST_ORACLE_DSN"],
